INSERT INTO `collection_book` (`id`, `item_id`, `name`, `info`, `icon`, `rank`, `max_amount`, `type`, `mob_id`, `head`, `body`, `leg`, `bag`, `options`, `aura`) VALUES
(1, 828, 'Thẻ Khủng long', 'Hai chi trước của Khủng long rất ngắn nên chúng không thể cầm thức ăn được', 7467, 0, 120, 0, 1, -1, -1, -1, -1, '[{\"param\":10,\"active_card\":0,\"id\":6},{\"param\":15,\"active_card\":1,\"id\":6},{\"param\":25,\"active_card\":2,\"id\":6}]', -1),
(2, 829, 'Thẻ Lợn lòi', 'Lợn lòi có sở thích mài răng nanh dưới đất, vô tình tạo ra những rãnh đất để người Namec trồng trọt', 7468, 0, 120, 0, 2, -1, -1, -1, -1, '[{\"param\":10,\"active_card\":0,\"id\":7},{\"param\":15,\"active_card\":1,\"id\":7},{\"param\":25,\"active_card\":2,\"id\":7}]', -1),
(3, 830, 'Thẻ Quỷ đất', 'Bản tính của Qủy đất khá nhút nhát, chúng thường núp vào cây khi gặp người lạ', 7469, 0, 120, 0, 3, -1, -1, -1, -1, '[{\"param\":1,\"active_card\":0,\"id\":0},{\"param\":3,\"active_card\":1,\"id\":0},{\"param\":5,\"active_card\":2,\"id\":0}]', -1),
(4, 831, 'Thẻ Khủng long mẹ', 'Hai chi trước của Khủng long rất ngắn nên chúng không thể cầm thức ăn được', 7470, 1, 100, 0, 4, -1, -1, -1, -1, '[{\"param\":15,\"active_card\":0,\"id\":6},{\"param\":25,\"active_card\":1,\"id\":6},{\"param\":50,\"active_card\":2,\"id\":6}]', -1),
(5, 832, 'Thẻ Lợn lòi mẹ', 'Lợn lòi có sở thích mài răng nanh dưới đất, vô tình tạo ra những rãnh đất để người Namec trồng trọt', 7471, 1, 100, 0, 5, -1, -1, -1, -1, '[{\"param\":15,\"active_card\":0,\"id\":7},{\"param\":25,\"active_card\":1,\"id\":7},{\"param\":50,\"active_card\":2,\"id\":7}]', -1),
(6, 833, 'Thẻ Quỷ đất mẹ', 'Bản tính của Qủy đất khá nhút nhát, chúng thường núp vào cây khi gặp người lạ', 7472, 1, 100, 0, 6, -1, -1, -1, -1, '[{\"param\":3,\"active_card\":0,\"id\":0},{\"param\":5,\"active_card\":1,\"id\":0},{\"param\":7,\"active_card\":2,\"id\":0}]', -1),
(7, 834, 'Thẻ Thằn lằn bay', 'Thằn lằn bay dùng cái mỏ dài và cứng để tấn công kẻ thù, đôi khi chúng vẫn dùng để gõ hạt óc chó ăn', 7473, 2, 80, 0, 7, -1, -1, -1, -1, '[{\"param\":1,\"active_card\":0,\"id\":27},{\"param\":3,\"active_card\":1,\"id\":27},{\"param\":5,\"active_card\":2,\"id\":27}]', -1),
(8, 835, 'Thẻ Phi long', 'Dùng tốc độ cực nhanh để tiếp cận và hạ gục mục tiêu, Phi long cũng có sở thích hơi lạ là khi bay luôn mở to miệng để đón gió', 7474, 2, 80, 0, 8, -1, -1, -1, -1, '[{\"param\":1,\"active_card\":0,\"id\":28},{\"param\":3,\"active_card\":1,\"id\":28},{\"param\":5,\"active_card\":2,\"id\":28}]', -1),
(9, 836, 'Thẻ Quỷ bay', 'Sở trường tấn công chớp choáng kẻ thù, nhưng đâu ai ngờ Quỷ bay lại có bệnh sợ độ cao', 7475, 2, 80, 0, 9, -1, -1, -1, -1, '[{\"param\":5,\"active_card\":0,\"id\":47},{\"param\":10,\"active_card\":1,\"id\":47},{\"param\":15,\"active_card\":2,\"id\":47}]', -1),
(10, 837, 'Thẻ Lính độc nhãn', 'Người ta nuôi quân lính dùng trong 1 giờ, Lính độc nhãn thì không dùng được 5 phút', 7476, 3, 60, 0, 34, -1, -1, -1, -1, '[{\"param\":30,\"active_card\":0,\"id\":7},{\"param\":5,\"active_card\":1,\"id\":0},{\"param\":50,\"active_card\":2,\"id\":6}]', -1),
(11, 838, 'Thẻ Lính độc nhãn', 'Người ta nuôi quân lính dùng trong 1 giờ, Lính độc nhãn thì không dùng được 5 phút', 7477, 3, 60, 0, 35, -1, -1, -1, -1, '[{\"param\":30,\"active_card\":0,\"id\":6},{\"param\":50,\"active_card\":1,\"id\":7},{\"param\":5,\"active_card\":2,\"id\":0}]', -1),
(12, 839, 'Thẻ Sói xám', 'Được lính độc nhãn thuần hóa và cho giữ nhà như cún con, sở thích của chúng là được chơi trò nhặt bóng', 7478, 3, 60, 0, 36, -1, -1, -1, -1, '[{\"param\":5,\"active_card\":0,\"id\":0},{\"param\":30,\"active_card\":1,\"id\":7},{\"param\":50,\"active_card\":2,\"id\":6}]', -1),
(13, 840, 'Thẻ Trung úy Trắng', 'Thân hình hơi béo so với tiêu chuẩn chung, luôn đeo chiếc khăn quàng đỏ, thường hay mơ mộng làm thơ', 7480, 4, 40, 1, -1, 141, 142, 143, -1, '[{\"param\":15,\"active_card\":0,\"id\":47},{\"param\":15,\"active_card\":1,\"id\":0},{\"param\":50,\"active_card\":2,\"id\":47},{\"param\":100,\"active_card\":3,\"id\":47},{\"param\":200,\"active_card\":4,\"id\":47}]', -1),
(14, 841, 'Thẻ Ninja Áo Tím', 'Ninja với nhiều tài năng để trở thành sát thủ, nhưng kỹ thuật ẩn thân lại không có, nên không thể trở thành sát thủ', 7481, 4, 40, 1, -1, 123, 124, 125, -1, '[{\"param\":100,\"active_card\":0,\"id\":7},{\"param\":1,\"active_card\":1,\"id\":114},{\"param\":1,\"active_card\":2,\"id\":114},{\"param\":1,\"active_card\":3,\"id\":114},{\"param\":1,\"active_card\":4,\"id\":114}]', -1),
(15, 842, 'Thẻ Trung úy Xanh Lơ', 'Có siêu năng lực thôi miên nhưng cực kỳ sợ chuột', 7479, 4, 40, 1, -1, 135, 136, 137, -1, '[{\"param\":100,\"active_card\":0,\"id\":6},{\"param\":20,\"active_card\":1,\"id\":0},{\"param\":20,\"active_card\":2,\"id\":0},{\"param\":20,\"active_card\":3,\"id\":0},{\"param\":20,\"active_card\":4,\"id\":0}]', -1),
(16, 859, 'Thẻ Độc Nhãn', 'Đầu não của Red Ribbon. Bị chột một mắt. Lúc nhỏ bị mọi người chê là \'Thằng lùn\'', 1568, 5, 40, 1, -1, 144, 145, 146, -1, '[{\"param\":1,\"active_card\":0,\"id\":175},{\"param\":2,\"active_card\":1,\"id\":175},{\"param\":3,\"active_card\":2,\"id\":175},{\"param\":3,\"active_card\":3,\"id\":175},{\"param\":3,\"active_card\":4,\"id\":175}]', -1),
(17, 956, 'Thẻ Đội trưởng Vàng', 'Đội trưởng Vàng là một con hổ hình người chắc nịch có cơ thể được bao phủ bởi bộ lông màu vàng, Goku đã đấm hắn ra khỏi máy bay của mình khi đang ở giữa không trung.', 8935, 4, 20, 1, -1, 994, 995, 996, -1, '[{\"param\":1,\"active_card\":0,\"id\":50},{\"param\":2,\"active_card\":1,\"id\":50},{\"param\":3,\"active_card\":2,\"id\":50},{\"param\":3,\"active_card\":3,\"id\":50},{\"param\":3,\"active_card\":4,\"id\":50},{\"param\":3,\"active_card\":5,\"id\":50},{\"param\":3,\"active_card\":6,\"id\":50},{\"param\":3,\"active_card\":7,\"id\":50},{\"param\":3,\"active_card\":8,\"id\":50}]', 18);
