INSERT INTO `news_posts` (`id`, `user_id`, `category_id`, `slug`, `title`, `short_content`, `content`, `thumbnail`, `views`, `status`, `created_at`, `updated_at`) VALUES
(1, 1, 1, 'Cẩm Nang Tân Thủ Cho Người Mới', 'Cẩm Nang Tân Thủ Cho Người Mới', 'Cẩm Nang Tân Thủ Cho Người Mới', '<div class=\"post-date\">21:36:02 29/06/2023</div>\n<div class=\"post-content\">\n  <p><strong>Không kích hoạt có chơi được game không?</strong></p>\n  <p>\n    Có nhé, nhưng sẽ bị giới hạn tính năng giao dịch, chỉ khi anh em kích hoạt\n    thì mới có thể giao dịch với người khác\n  </p>\n  <p><br /></p>\n  <p><strong>Tại sao tôi không Xác Thực Tài Khoản được?</strong></p>\n  <p>\n    Các bạn vào mục tải về, tải lại bản V148 mới nhất, sau đó vào lại game rồi\n    xác thực là được nhé\n  </p>\n  <p><br /></p>\n  <p><strong>Làm sao để nhận quà tân thủ?</strong></p>\n  <p>\n    Khi vào game, anh em lại NPC Admin ở Làng Tone để nhận quà tân thủ, tiếp đó\n    lại NPC Okanechan để nhập code: \"tanthu\" để nhận thêm một lần nữa, ngoài ra\n    anh em có thể nhận Thưởng Thăng Cấp tại NPC Okanechan mỗi khi đạt một mốc\n    cấp độ nào đó\n  </p>\n  <p><br /></p>\n  <p><strong>Hiện tại có những CODE gì cho người mới?</strong></p>\n  <p>\n    Hiện tại đang có code là <strong>tanthu</strong> cho những anh em mới\n    chơi nhé, để nhận thêm CODE anh em có thể tham gia các hoạt động trên\n    Fanpage, chúng mình thường xuyên tổ chức để phát code cho người chơi nè\n  </p>\n  <p><br /></p>\n  <p><strong>Android nên chơi bản nào để ổn định nhất?</strong></p>\n  <p>\n    Hiện tại để chơi trên Android ổn định nhất các bạn nên chơi bản Java bằng\n    cách tải J2ME Loader trên CH PLAY, sau đó tải bản Java Auto về và mở J2ME\n    Loader lên để chạy nhé\n  </p>\n  <p><br /></p>\n  <p><strong>PC nên chơi bản nào để ổn định nhất?</strong></p>\n  <p>Hiện tại PC các bạn nên chơi giả lập Java là ổn định nhất nhé</p>\n  <ul>\n    <li>\n      B1: Tải Microemulator:\n      <a\n        href=\"https://angelchip.net/files/share/AngelChipEmulatorEXE.zip\"\n        rel=\"noopener noreferrer\"\n        target=\"_blank\"\n        style=\"color: rgb(0, 102, 204)\"\n        >AngelChipEmulator.zip</a\n      >\n    </li>\n    <li>\n      B2: Tải Game:<span style=\"color: rgb(0, 102, 204)\"> </span\n      ><a\n        href=\"https://nsochen.pro/download\"\n        rel=\"noopener noreferrer\"\n        target=\"_blank\"\n        style=\"color: rgb(0, 102, 204)\"\n        >Tại đây</a\n      >\n      hoặc bạn có thể tải bản khác ở mục TẢI GAME\n    </li>\n    <li>B3: Giải nén và mở microemulator đã tải về</li>\n    <li>B4: Kéo bản java vào microemulator và chạy thôi</li>\n  </ul>\n  <p><strong>Trên bản IOS tại sao di chuyển lại bị dật lại?</strong></p>\n  <p>Các bạn chat s6 để giảm tốc độ chạy là được nhé</p>\n  <p><br /></p>\n  <p>\n    <strong\n      >Tại sao nick tôi bị kẹt, đăng nhập không được, hoặc vào Vùng đất ma quỷ\n      bị lag game?</strong\n>\n  </p>\n  <p>\n    Đối với bản Android và IOS hiện tại đang bị lỗi lag game ở Vùng Đất Ma Quỷ,\n    với Android các bạn có thể chơi bằng J2ME Loader như hướng dẫn bên trên, còn\n    IOS thì sắp tới chúng mình sẽ fix lại nhé ạ\n  </p>\n  <p><br /></p>\n  <p><strong>Chơi Android không thể gán chiêu, phải làm thế nào?</strong></p>\n  <p>\n    Tương tự như trên, bản Android cũng đang bị lỗi này, các bạn chơi bằng J2ME\n    Loader như hướng dẫn bên trên để ổn định nhé\n  </p>\n  <p><br /></p>\n  <p><strong>Tại sao đánh quái không nhận được kinh nghiệm?</strong></p>\n  <p>Có 2 trường hợp xảy ra:</p>\n  <ul>\n    <li>Do bạn đánh quái nằm ngoài khoảng +/-10 level</li>\n    <li>Do bạn tắt nhận EXP ở NPC Admin</li>\n  </ul>\n  <p>\n    <strong\n      >Mới chơi GAME, mua bán nick nhưng không biết nên giao dịch thế\n      nào?</strong\n    >\n  </p>\n  <p>\n    Ở mỗi BOX ZALO bên dưới đều sẽ có GIAO DỊCH VIÊN (KEY BẠC), anh em liên hệ\n    những GDV này để làm trung gian tránh lừa đảo khi giao dịch trực tiếp nhé\n  </p>\n  <p><br /></p>\n  <p><strong>Tại sao sử dụng vật phẩm sự kiện không nhận được EXP?</strong></p>\n  <p>\n    Hiện tại đang có Tái Lập Đua TOP, anh em tạo tài khoản vào thời gian này sẽ\n    mặc định đưa vào danh sách đua top, các bạn có thể lại NPC ADMIN hủy đua TOP\n    để nhận được EXP khi dùng vật phẩm sự kiện nhé\n  </p>\n  <p><br /></p>\n  <p>\n    <strong style=\"color: rgb(94, 98, 120)\"\n      >Tại sao đánh quái không rơi vật phẩm?</strong\n    >\n  </p>\n  <p>Các bạn chỉ đánh quái nằm trong khoảng +/-7 level thôi nhé</p>\n  <p><br /></p>\n  <p><strong>NsoPro có nhóm cộng đồng nào không?</strong></p>\n  <p>Không những có mà là có rất nhiều nha:</p>\n  <ul>\n    <li>\n        Group Zalo 1:\n        <a\n          href=\"https://zalo.me/g/taahcl325\"\n          rel=\"noopener noreferrer\"\n          target=\"_blank\"\n          >https://zalo.me/g/taahcl325</a\n        ></br>\n        Group Zalo 2:\n        <a\n          href=\"https://zalo.me/g/taahcl325\"\n          rel=\"noopener noreferrer\"\n          target=\"_blank\"\n          >https://zalo.me/g/taahcl325</a\n        >\n\n      </li>\n  </ul>\n</div>\n', '', 1418, 0, NULL, NULL),
(2, 1, 1, 'Thông tin về Server', 'Thông tin về Server', 'Thông tin về Server', '<div class=\"post-date\">20:36:02 29/06/2023</div>\n<div class=\"post-content\">\n  <p>☀️ Ninja School Online Lậu - Server Cày Chay Nhận Lượng Mỗi Ngày Không Nạp Mà Cũng Có Ăn\nTặng Lượng Mỗi Ngày</p>\n  <p>\n    ☀️ Server ĐẦU TIÊN có <b>bản hack cho cả IOS, PC và Android</b>\n  </p>\n  <p>☀️ Server đầu tiên có lever 150</p>\n  <p>☀️ Server đầu tiên có map cho ae cày yên từ lv 100-150 riêng biệt không chung đụng ae lv thấp không lo giành map mỗi người 1 map cực kì thích</p>\n  <p>\n    ☀️ Có trang bị 10x siêu mới mẻ update liên tục\n  </p>\n  <p>☀️ Chiêu thức 12x cực kì mới</p>\n  <p>☀️ Làm lại skill phái Quạt và Đao hồi chiêu cực nhanh chỉ 0.35s</p>\n  <p>\n   ☀️ Server chuẩn như sever gốc không lạm phát\n  </p>\n<p>☀️ Tính năng nâng theo mức độ nhiệm vụ chính tuyến, Chuyển sinh được phát triển lần đầu tiên</p>\n  <p>☀️ Tính năng KHAI HOÁ, THĂNG LƯỠNG được phát triển lần đầu tiên</p>\n  <p>☀️ Chiến trường HẮC BẠCH GIẢ với những thay đổi cực mới lạ</p>\n  <p>\n<p>☀️ Tính năng săn Vĩ Thú (sắp ra mắt )</p>\n    ☀️ Hoạt động cày Fan cứng nhận Giftcode hàng tháng\n  </p>\n  <p>-----------------------------------------------</p>\n\n  <ul>\n    <li>\n     🌐 Trang chủ và tải game: \n      <a\n        href=\"https://nsochen.pro/\"\n        target=\"_blank\"\n        style=\"color: rgb(0, 102, 204)\"\n        >https://nsochen.pro/</a\n      >\n    </li>\n<li>\n      🔔 KÊNH YOUTUBE : \n      ><a\n        href=\"https://youtube.com/@quangchentwvn?si=uNJKF3vKhRQ1SeuQ\"\n        rel=\"noopener noreferrer\"\n        target=\"_blank\"\n        style=\"color: rgb(0, 102, 204)\"\n        >https://youtube.com/@quangchentwvn?si=uNJKF3vKhRQ1SeuQ</a\n      >\n    </li>\n    <li>\n      🔔 Group Facebook : \n      ><a\n        href=\"https://www.facebook.com/groups/1025502525288970/?ref=share_group_link\"\n        rel=\"noopener noreferrer\"\n        target=\"_blank\"\n        style=\"color: rgb(0, 102, 204)\"\n        >https://www.facebook.com/groups/1025502525288970/?ref=share_group_link</a\n      >\n      hoặc bạn có thể tải bản khác ở mục TẢI GAME\n    </li>\n    <li>🔹 Group Zalo 2 : \n	<a\n        href=\"https://zalo.me/g/taahcl325\"\n        rel=\"noopener noreferrer\"\n        target=\"_blank\"\n        style=\"color: rgb(0, 102, 204)\"\n        >https://zalo.me/g/taahcl325</a\n      >\n      \n      </li>\n          <li>🔹 Group Zalo 1 : \n	<a\n        href=\"https://zalo.me/g/taahcl325\"\n        rel=\"noopener noreferrer\"\n        target=\"_blank\"\n        style=\"color: rgb(0, 102, 204)\"\n        >https://zalo.me/g/taahcl325</a\n      >\n      \n      </li>\n  </ul>\n  \n</div>\n', '', 936, 0, NULL, NULL);
INSERT INTO `notifications` (`id`, `title`, `content`) VALUES
(1, 'Thông Báo', 'Mọi thông tin có thể tham khảo tại trang chủ daichienrongthan.net'),
(2, 'Giải đáp thắc mắc về Game!', 'Bạn có thắc mắc về Game? Tui sẽ giải đáp!!\r\n -SKH : up 2 map sau làng các hành tinh\r\n -SKH VIP : Nâng cấp Skh Vip bên Bà hạt mít (max cấp là đồ Thần linh)\r\n -Đồ thần : up Cold hoặc săn Boss\r\n -Đồ Huỷ diệt : Nâng cấp từ đồ Thần linh bên Bà hạt mít, mua trên Bill ở Kaio\r\n -Thức ăn : Mang 5 món thần linh qua Tương lai up sên\r\n -Mảnh thiên sứ : mang 5 món Huỷ diệt qua Hành tinh ngục tù (gặp Osin ở Hành tinh Bill)\r\n -Đá cầu vòng : Săn Boss Thiên sứ ở Hành tinh Bill\r\n -Đồ Thiên sứ : Gặp Whis ở Hành tinh Bill có mọi thông tin\r\n -Chỉ số Bông tai Max : C2 là 15%, C3 là 25%, C4 là 35%\r\n -Mảnh vỡ BT up map 123 Lãnh địa bang, mảnh hồn up map 4\r\n -Đồ max 8 sao và 8 cấp, Chỉ số HPG KIG max 1 Triệu, SDG 60k, Giáp 2100, CM gốc 14%\r\n -Pha lê hoá được Cải trang, Giáp luyện tập và Đồ\r\n -6 ô cuối hành trang lần lượt là : Pet, Danh hiệu (vp đeo lưng), Thú cưỡi, Linh thú, Chân mệnh, Sách tuyệt kĩ'),
(3, 'CÁC LỆNH CHO MEMBER', 'tt : Hiện thông tin Bản thân, Đồ mặc');
