INSERT INTO `task_main_template` (`id`, `NAME`, `detail`) VALUES
(0, 'Nhiệm vụ đầu tiên', 'Chi tiết nhiệm vụ'),
(1, 'Nhiệm vụ tập luyện', 'Mộc nhân được đặt nhiều tại %1, ngay trước nhà ông %2\nHãy đánh ngã 1 mộc nhân, \r\nsau đó quay về nhà báo cáo với ông %2\nĐể đánh, hãy chạm nhanh 2 lần vào đối tượng\nThưởng 1000 sức mạnh\nThưởng 1000 tiềm năng'),
(2, 'Nhiệm vụ tìm thức ăn', 'Tìm đến %3, tiêu diệt bọn quái %4 và nhặt về 10 đùi gà\nThưởng 1200 sức mạnh\nThưởng 1200 tiềm năng\nHọc được kỹ năng bay'),
(3, 'Tìm kiếm sao băng', 'Đi khám phá xem vật thể lạ vừa rơi xuống hành tinh\nThưởng 3000 sức mạnh\nThưởng 3000 tiềm năng'),
(4, 'Nhiệm vụ khó khăn', 'Đi tới %6, tiêu diệt lũ %4 mẹ\nThưởng 7000 sức mạnh\nThưởng 7000 tiềm năng'),
(5, 'Nhiệm vụ gia tăng sức mạnh', 'Hãy đi tập luyện để gia tăng sức mạnh\nThưởng 20000 sức mạnh\nThưởng 20000 tiềm năng'),
(6, 'Nhiệm vụ trò chuyện', 'Đi tới trạm tàu vũ trụ, trò chuyện với %7'),
(7, 'Nhiệm vụ giải cứu', 'Lên đường tiêu diệt bọn %9, giải cứu %8\nQuay về báo cáo với %7 để nhận thưởng'),
(8, 'Nhiệm vụ ân nhân xuất sắc', 'Về %1, gặp và trò chuyện với %8\nSau đó về nhà kể lại mọi chuyện với ông %2'),
(9, 'Nhiệm vụ tiên học lễ', 'Tìm đường tới %11, trò chuyện với %10 và xin làm đệ tử'),
(10, 'Nhiệm vụ học phí', 'Tiêu diệt %12 thể hiện sức mạnh cho %10 thấy'),
(11, 'Nhiệm vụ kết giao', 'Thể hiện thiện chí đoàn kết\nMở rộng các mối quan hệ\nKết bạn với người chưa có bang hội'),
(12, 'Nhiệm vụ xin phép', 'Quay về nhà xin ông %2 cho phép tham gia bang hội cái bang'),
(13, 'Nhiệm vụ gia nhập bang hội', 'Gia nhập 1 bang hội cùng những người đồng đội thiện chí\nCùng làm nhiệm với nhau không quản khó khăn'),
(14, 'Nhiệm vụ bang hội lần 1', 'Cùng phối hợp với 2 người đồng đội lên đường làm nhiệm vụ\r\nGợi ý:\r\nHeo rừng xuất hiện tại rừng Bamboo\r\nHeo da xanh xuất \r\nhiện tại núi hoa vàng\r\nHeo xayda xuất hiện tại rừng cọ\r\nHãy tới trạm tàu vũ trụ để có thể di chuyển qua các map'),
(15, 'Nhiệm vụ bang hội lần 2', 'Hãy cùng 2 người đồng đội bang hội của mình để chiến đấu hết mình nha'),
(16, 'Tiêu diệt quái vật', 'Tới các hành tinh tiêu diệt quái vật, giải cứu thường dân'),
(17, 'Nhiệm vụ giúp đỡ Cui', 'Tìm đường tới thành phố Vegeta, gặp và nói chuyện với Cui'),
(18, 'Nhiệm vụ bất khả thi', 'Tiêu diệt đàn em tay sai của Fide tại Xayda. Thưởng 1000 Hồng ngọc'),
(19, 'Nhiệm vụ chạm trán đệ tử', 'Tiêu diệt đàn em tay sai của Fide. Thưởng 2000 Hồng ngọc'),
(20, 'Nhiệm vụ Tiểu Đội Sát Thủ', 'Tiêu diệt 5 tên trong đội Tiểu Đội Sát Thủ. Thưởng 3000 Hồng ngọc'),
(21, 'Nhiệm vụ chạm trán Fide đại ca', 'Luyện tập đạt 2 tỷ sức mạnh\nLên đường tìm diệt Fide đại ca. Thưởng 4000 Hồng ngọc'),
(22, 'Nhiệm vụ chạm trán Rôbốt sát thủ lần 1', 'Hãy đến thành phố phía Nam, đảo Balê hoặc Cao nguyên tìm gặp Rôbốt sát thủ để tiêu diệt. Thưởng 5000 Hồng ngọc'),
(23, 'Nhiệm vụ chạm trán Rôbốt sát thủ lần 2', 'Hãy đến thành phố phía Bắc, ngọn núi phía Bắc hoặc thung lũng phía Bắc tìm diệt bọn Rôbốt sát thủ. Thưởng 6000 Hồng ngọc'),
(24, 'Nhiệm vụ giải cứu thị trấn Ginder', 'Lên đường tới thị trấn Ginder, tiêu diệt nỗi hiểm họa gần đây tại thị trấn Ginder. Thưởng 7000 Hồng ngọc'),
(25, 'Tiêu Diệt Xên', 'Hành trình tích lũy kinh nghiệm tại tương lai\r\nĐến tương lai và diệt cái quái Xên theo yêu cầu. Thưởng 8000 Hồng ngọc'),
(26, 'Tiêu Diệt Xên Lần 2', 'Hành trình tích lũy kinh nghiệm tại tương lai\r\nĐến tương lai và diệt cái quái Xên theo yêu cầu. Thưởng 9000 Hồng ngọc'),
(27, 'Kết Bạn Nhìu Niềm Vui', 'Săn Boss Sên tại võ đài và thu thập Ngọc rồng 2s từ chúng. Thưởng 10000 Hồng ngọc'),
(28, 'Săn Xên Bên Võ Đài Nhé', 'Cùng càn quét và tiêu diệt mối nguy hại bên Tương lai để giải cứu thế giới nào !!!. Thưởng 15000 Hồng ngọc'),
(29, 'Qua Cold Nhé', 'Đến Thành phố Vegeta gặp Cui để đến Hành tinh Cold. Thưởng 17500 Hồng ngọc'),
(30, 'Càn quét Tương lai', 'Vui lòng chờ nhiệm vụ tiếp theo..... Thưởng 20000 Hồng ngọc'),
(31, 'Nhiệm Vụ Hơi Khó Nhé Nên Sẽ Có Nhiều Em Kẹt Ở Đây', 'Bạn Chỉ Có 20% Cơ Hội Để Vượt Qua Nhiệm Vụ Này. Thưởng 25000 Hồng ngọc'),
(32, 'Hành trình Du hành thời không', 'Đến Hành tinh Nguyên thủy cùng khám phá nhiều thứ mới nào\r\nTìm và gặp Bardock và Berry tại Khu hang động. Thưởng 30000 Hồng ngọc'),
(33, 'Nhiệm vụ Bất khả thi 2', 'Chỉ có kẻ siêng năng mới thành công. Thưởng 35000 Hồng ngọc');
